ControlPropertyState.AutoRuleBindingString:
//////////////////////////////////////////////////////////////////////////////////////////
// Update checklist form (response) and update Technician Status to submitted

Patch(
    tbl_mrl_workorder_assign,
    LookUp( tbl_mrl_workorder_assign, ID = varSelectedTask.ID ),
    {
        response: varChecklistOutput,
        status: {
            Id:5, 
            Value:"Submitted"
        },
        end_date: Now()
    }
);

// log tbl_mrl_workorder_assign_log status Processing
Patch(
    tbl_mrl_workorder_assign_log,
    Defaults(tbl_mrl_workorder_assign_log),
    {
        workorder_assign_id: varSelectedTask.ID,
        workorder_no_ref: Round(varSelectedTask.workorder.Value,0),
        workorder_status: "Submitted",
        user_email: varUserRecord.email,
        user_role: varUserRecord.role.Value,
        user_department: varUserRecord.department.Value,
        location_long: Location.Longitude,
        location_lat: Location.Latitude
    }
);



//////////////////////////////////////////////////////////////////////////////////////////
// Check all techinician submit workorder

UpdateContext({
    countAllTechnician:         
        CountRows(
            Filter(
                tbl_mrl_workorder_assign, 
                workorder.Id = varSelectedTask.workorder.Id
                )
            ),
    countSubmittedTechnician:   
        CountRows(
            Filter(
                tbl_mrl_workorder_assign, 
                workorder.Id = varSelectedTask.workorder.Id && status.Value = "Submitted"
            )
        )
});

If (
    // Check All Technician Submitted Task
    countAllTechnician = countSubmittedTechnician,

    // Then Update to RTC
   Patch(
        tbl_mrl_workorder,
        LookUp(tbl_mrl_workorder, ID = varSelectedTask.workorder.Id),
        {
            status_workorder_dmp: {
                Id: 4,
                Value: "RTC"
            }
        }
   );

    // log tbl_mrl_workorder_log status RTC
    Patch(
        tbl_mrl_workorder_log,
        Defaults(tbl_mrl_workorder_log),
        {
            workorder_no_ref: varSelectedTask.workorder.Value,
            workorder_status: "RTC",
            user_email: varUserRecord.email ,
            user_role: varUserRecord.role.Value,
            user_department: varUserRecord.department.Value,
            location_long: Location.Longitude,
            location_lat: Location.Latitude
        }
    );
   ,
    // else
    true
);



//////////////////////////////////////////////////////////////////////////////////////////
// Update response to tbl_mrl_workorder 
// Conflict-Free Merging Logic (Bypasses Table/ParseJSON errors)

// 1. Initialize and clear the collection to define schema
ClearCollect(colFinalMerged, {Key: "", Val: ""});
Clear(colFinalMerged);

// Load all relevant responses into a local collection to avoid delegation issues
ClearCollect(colRawResponses, 
    Filter(tbl_mrl_workorder_assign, workorder.Id = varSelectedTask.workorder.Id && !IsBlank(response))
);


// 2. Loop through all rows for this specific WorkOrder
ForAll(
    colRawResponses,
    With({
        // Remove curly braces and escaping backslashes that cause parsing errors
        cleanBody: Substitute(Substitute(Substitute(Substitute(response, "{", ""), "}", ""), "\", ""), """", "")
    },
    ForAll(
        Split(cleanBody, ","),
        With({
            // Separate Key and Value (e.g., "1.1.a.ECA1:true")
            rawKey: Trim(First(Split(Value, ":")).Value),
            rawVal: Trim(Last(Split(Value, ":")).Value)
        },
        If(!IsBlank(rawKey),
            // Remove existing key to prevent duplicates (Conflict Resolution)
            RemoveIf(colFinalMerged, Key = rawKey);
            Collect(colFinalMerged, { Key: rawKey, Val: rawVal })
        )
    ))
));


// 4. Create the final clean JSON string
UpdateContext({
    varMasterJson: "{" & Concat(colFinalMerged, $"""{Key}"":{Val}", ",") & "}"
});


// 5. Patch to the Master Table (tbl_mrl_workorder)
Patch(
    tbl_mrl_workorder,
    LookUp(tbl_mrl_workorder, workorder_no = varSelectedTask.workorder.Value), 
    {
        completed_response:  JSON(
            varMasterJson, 
            JSONFormat.IgnoreBinaryData
        )
    }
);


UpdateContext({
    varChecklistPMDialog : false
});
Notify("Task Successfully Submitted");
Navigate(TASK_LIST);

//////////////////////////////////////////////////////////////////////////////////////////
// Update checklist form (response) and update Technician Status to submitted

Patch(
    tbl_mrl_workorder_assign,
    LookUp( tbl_mrl_workorder_assign, ID = workorderAssignId ),
    {
       verify_status: "true"
    }
);

UpdateContext({
    isPopUpTechConfirmClose : false
});
Notify("Checklist Form Successfully Reviewed");
Navigate(WORKORDER_VIEW_ASSIGNED_TECHNICIAN_SV);
